        cout << "相等" << endl;
    }

    return 0;
}

#include <iostream>
#include <string>
using namespace std;

int main() {
    string s = "Hello, C++!";

    cout << "原字符串：" << s << endl;
    cout << "长度：" << s.length() << endl;

    // 截取子串
    string sub = s.substr(0, 5);
    cout << "子串：" << sub << endl;

    // 查找
    int pos = s.find("C++");
    cout << "C++位置：" << pos << endl;

    // 替换
    s.replace(pos, 3, "Java");
    cout << "替换后：" << s << endl;

    return 0;
}

