#include <iostream>
#include <string>
using namespace std;

int main() {
    string s = "Hello, C++!";

    // 统计小写字母个数
    int count = 0;
    for (char c : s) {
        if (c >= 'a' && c <= 'z') {
            count++;
        }
    }
    cout << "小写字母个数：" << count << endl;

    // 转换为小写
    for (int i = 0; i < s.length(); i++) {
        if (s[i] >= 'A' && s[i] <= 'Z') {
            s[i] += 32;
        }
    }
    cout << "小写：" << s << endl;

    return 0;
}

#include <iostream>
#include <string>
using namespace std;

int main() {
    string s, s1, s2;
    getline(cin, s);
    cin >> s1 >> s2;

    int pos = s.find(s1);
    while (pos != string::npos) {
        s.replace(pos, s1.length(), s2);
        pos = s.find(s1, pos + s2.length());
    }

    cout << s << endl;
    return 0;
}
